<template>
  <section id="gallery">
    <gallery :items="set" />
  </section>
</template>

<script>
import gallery from '@/components/gallery'
import { main } from '@/components/galleries'

  export default {
    name: 'mainGallery',
    components: {
      gallery
    },
    data() {
      return {
        set: null
      }
    },
    created () {
      this.set = main
    }
  }
</script>


