<template>
  <section id="social">
    <ul class="grid-list">
      <li v-for="site in sites" :key="site.name">
        <a :href="site.url" :title="(site.username || defaults.username)" target="_blank"><ico :icon='icon(site)' fixed-width /></a>
        {{ site.name }}
      </li>
    </ul>
  </section>
</template>
<script>
export default {
  name: 'social',
  methods: {
    icon (x) {
      if (x.icon) return x.icon
      else {
        return ['fab', x.name ]
      }
    }
  },
  data () {
    return {
      defaults: {username: 'caebbage'},
      sites: [
        {
          name: 'twitter',
          url: 'https://twitter.com/caebbage'
        },
        {
          name: 'instagram',
          url: 'http://instagram.com/caebbage'
        },
        {
          name: 'weibo',
          username: '海盐雪糕',
          url: 'https://weibo.com/u/6419948158/'
        },
        {
          name: 'youtube',
          username: 'cae draws',
          url: 'https://www.youtube.com/channel/UCy3JHV4GGSSfh_XAi8j8D4w'
        },
        {
          name: 'twitch',
          url: 'https://www.twitch.tv/caebbage'
        },
        {
          name: 'tumblr',
          username: 'asgr-memo',
          url: 'http://asgr-memo.tumblr.com/'
        },
        {
          name: 'pixiv',
          icon: 'star',
          username: '★',
          url: 'http://pixiv.me/mncpa'
        },
        {
          name: 'ko-fi',
          icon: 'coffee',
          url: 'http://ko-fi.com/caebbage'
        },
        {
          name: 'curious cat',
          icon: 'question-circle',
          url: 'https://curiouscat.me/caebbage'
        },
        {
          name: 'deviantart',
          username: 'teruva',
          url: 'https://teruva.deviantart.com/'
        }
      ]
    }
  }
}
</script>


