<template>
  <div
  :class="'modal-wrap' + ((name) ? ' ' + name : '') + ((content) ? '' : ' inactive')"
  v-on:click="control.unset()"
  >
    <div class="modal-exit fas fa-times" v-on:click="control.unset()">

    </div>
    <div class="modal-container" v-on:click.stop>
      <div class="modal-content">
        <slot>

        </slot>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'modal',
  props: ['content', 'name', 'control']
}
</script>


